-                    if (std.mem.eql(u8, col.name, name)) {
-                        found = true;
-                        break;
-                    }
-                }
-                if (!found) {
-                    // Column not in schema - emit error at runtime
-                    try writer.print("@compileError(\"Column '{s}' not in schema\")", .{name});
-                    return;
-                }
-            }
