-/// Cached result from @logic_table function call
-pub const CachedResult = union(enum) {
-    f64_scalar: f64,
-    i64_scalar: i64,
-    f64_array: []f64,
-    i64_array: []i64,
-    f32_array: []f32,
-    bool_scalar: bool,
