-    pub fn deinit(self: *CachedResult, allocator: std.mem.Allocator) void {
-        switch (self.*) {
-            .f64_array => |arr| allocator.free(arr),
-            .i64_array => |arr| allocator.free(arr),
-            .f32_array => |arr| allocator.free(arr),
