-// =============================================================================
-// SIMD Vector Primitives
-// =============================================================================
-
-/// Dot product of two vectors
-fn vectorDot(a: []const f32, b: []const f32) f32 {
-    const len = @min(a.len, b.len);
-    var sum: f32 = 0;
-
-    // SIMD path for vectors >= 8 elements
-    if (len >= 8) {
-        const Vec8 = @Vector(8, f32);
-        var i: usize = 0;
-        var simd_sum: Vec8 = @splat(0);
-
-        while (i + 8 <= len) : (i += 8) {
