-/// Error type for logic_table dispatch
-pub const DispatchError = error{
-    ClassNotFound,
-    MethodNotFound,
-    ArgumentCountMismatch,
-    InvalidArgumentType,
-    ExecutionFailed,
-    OutputBufferNotInitialized,
-    OutOfMemory,
-};
